function detectContentType(filename) {
  const ext = path5.extname(filename).toLowerCase();
  const map = {
    ".txt": "text/plain",
    ".md": "text/markdown",
    ".html": "text/html",
    ".htm": "text/html",
    ".css": "text/css",
    ".js": "text/javascript",
    ".ts": "text/typescript",
    ".json": "application/json",
    ".xml": "application/xml",
    ".pdf": "application/pdf",
    ".png": "image/png",
    ".jpg": "image/jpeg",
    ".jpeg": "image/jpeg",
    ".gif": "image/gif",
    ".svg": "image/svg+xml",
    ".webp": "image/webp",
    ".mp4": "video/mp4",
    ".mp3": "audio/mpeg",
    ".wav": "audio/wav",
    ".zip": "application/zip"
  };
  return map[ext] ?? "application/octet-stream";
}

// ../server/dist/notifications/paperclip.js
function buildCommentBody(event, deliverable, feedback) {
  const eventLabel = {
    approved: "Approved",
    revision_requested: "Revision Requested",
    rejected: "Rejected"
  };
  const lines = [
    `## AROS Review: ${eventLabel[event]}`,
    "",
    `**Deliverable:** ${deliverable.title}`,
    `**Review ID:** ${deliverable.review_id}`,
    `**Revision:** ${deliverable.revision_number}`,
    ""
  ];
  if (feedback) {
    lines.push(`**Summary:** ${feedback.summary}`, "");
    if (feedback.issues.length > 0) {
      lines.push("### Issues", "");
      for (const issue2 of feedback.issues) {
        const file = issue2.file ? ` (${issue2.file})` : "";
        lines.push(`- **[${issue2.severity.toUpperCase()}]** ${issue2.description}${file}`, `  - Location: ${issue2.location}`, `  - Category: ${issue2.category}`, `  - Suggestion: ${issue2.suggestion}`, "");
      }
    }
  }
  return lines.join("\n");
}
var paperclipDriver = {
  name: "paperclip",
  validateTarget(target) {
    const required2 = ["api_url", "company_id", "issue_id"];
    for (const field of required2) {
      if (!target[field]) {
        return { valid: false, error: `Missing required target field: ${field}` };
      }
    }
    return { valid: true };
  },
  async send(event, deliverable, feedback, target) {
    const api_url = target["api_url"];
    const company_id = target["company_id"];
    const issue_id = target["issue_id"];
    const commentsUrl = `${api_url}/api/companies/${company_id}/issues/${issue_id}/comments`;
    const issueUrl = `${api_url}/api/companies/${company_id}/issues/${issue_id}`;
    const body = buildCommentBody(event, deliverable, feedback);
    try {
      const commentRes = await fetch(commentsUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ content: body })
      });
      if (!commentRes.ok) {
        return {
          success: false,
          error: `Paperclip comment POST failed: ${commentRes.status} ${commentRes.statusText}`
        };
      }
      if (event === "approved" || event === "rejected") {
        const newStatus = event === "approved" ? "done" : "blocked";
        const patchRes = await fetch(issueUrl, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ status: newStatus })
        });
        if (!patchRes.ok) {
          return {
            success: false,
            error: `Paperclip issue PATCH failed: ${patchRes.status} ${patchRes.statusText}`
          };
        }
      }
      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      return { success: false, error: `Paperclip fetch error: ${message}` };
    }
  }
};

// ../mcp/dist/tools/create-review.js
function registerCreateReview(server, storage2, reviewUrl) {
  server.tool("create_review", "Create a new review draft. Returns a review_id for use with add_file and submit_for_review. Prefer submit_deliverable instead \u2014 it combines create, add files, and submit in one call.", {
    title: external_exports.string().describe("Title of the deliverable"),
    brief: external_exports.string().describe("Brief description or requirements for the deliverable"),
    policy: external_exports.string().default("default").describe("Policy name to apply (defaults to 'default')"),
    source_agent: external_exports.string().describe("Identifier for the agent submitting the deliverable"),
    content_type: external_exports.string().describe("MIME type or description of the content (e.g. 'image/png', 'text/markdown')"),
    folder_strategy: external_exports.enum(["all_pass", "select", "rank", "categorize"]).optional().describe("Folder review strategy when multiple files are submitted"),
    notification_driver: external_exports.string().optional().describe("Notification driver name (e.g. 'paperclip')"),
    notification_target: external_exports.record(external_exports.unknown()).optional().describe("Notification target config object (driver-specific fields)"),
    notification_events: external_exports.array(external_exports.enum(["approved", "revision_requested", "rejected"])).optional().describe("Which events to trigger notifications for")
  }, async (args) => {
    try {
      if (args.notification_driver && args.notification_target) {
        const driver = getDriver(args.notification_driver);
        if (!driver) {
          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({ error: `Unknown notification driver: ${args.notification_driver}` })
              }
            ],
            isError: true
          };
        }
        const validation = driver.validateTarget(args.notification_target);
        if (!validation.valid) {
          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({ error: `Invalid notification target: ${validation.error}` })
              }
            ],
            isError: true
          };
        }
      }
      const meta = {
        title: args.title,
        brief: args.brief,
        policy: args.policy,
        source_agent: args.source_agent,
        content_type: args.content_type,
        ...args.folder_strategy ? { folder_strategy: args.folder_strategy } : {},
        ...args.notification_driver && args.notification_target ? {
          notification: {
            driver: args.notification_driver,
            target: args.notification_target,
            events: args.notification_events ?? ["approved", "revision_requested", "rejected"]
          }
        } : {}
      };
      const review_id = await storage2.createReview(meta);
      const url = await reviewUrl(review_id);
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({ review_id, review_url: url })
          }
        ]
      };
    } catch (err) {
      const error2 = err instanceof Error ? err.message : String(err);
      return {
        content: [{ type: "text", text: JSON.stringify({ error: error2 }) }],
        isError: true
      };
    }
  });
}

