    source_path: external_exports.string().optional().describe("Absolute path to a file on disk. AROS will copy it into the review. Preferred for large files, images, and binaries"),
    content: external_exports.string().optional().describe("Inline file content \u2014 UTF-8 text or base64-encoded binary. Use source_path instead for large files"),
    content_type: external_exports.string().optional().describe("MIME type (e.g. 'image/png', 'text/markdown'). Auto-detected from filename if omitted"),
